"""Word counter utility — 第 67 次自评小任务自测"""

from typing import Dict
import re


def count_words(text: str) -> Dict[str, int]:
    """统计文本中每个单词的出现次数（不区分大小写）。

    Args:
        text: 输入文本

    Returns:
        {word: count} 字典，按出现次数降序排列
    """
    if not text or not text.strip():
        return {}

    words = re.findall(r'\b\w+\b', text.lower())
    counts: Dict[str, int] = {}
    for word in words:
        counts[word] = counts.get(word, 0) + 1

    # 按次数降序排列
    return dict(sorted(counts.items(), key=lambda x: x[1], reverse=True))


def top_n_words(text: str, n: int = 5) -> list:
    """返回出现频率最高的 N 个单词。

    Args:
        text: 输入文本
        n: 返回的单词数量

    Returns:
        [(word, count), ...] 列表
    """
    counts = count_words(text)
    return list(counts.items())[:n]


# ── 测试 ──────────────────────────────────────────

import pytest


class TestCountWords:
    def test_basic(self):
        result = count_words("hello world hello")
        assert result == {"hello": 2, "world": 1}

    def test_case_insensitive(self):
        result = count_words("Hello HELLO hello")
        assert result == {"hello": 3}

    def test_empty(self):
        assert count_words("") == {}
        assert count_words("   ") == {}
        assert count_words(None) == {}

    def test_punctuation(self):
        result = count_words("hello, world! hello.")
        assert result["hello"] == 2
        assert result["world"] == 1

    def test_sorted_by_count(self):
        result = count_words("a b b c c c")
        keys = list(result.keys())
        assert keys == ["c", "b", "a"]

    def test_single_word(self):
        assert count_words("test") == {"test": 1}


class TestTopNWords:
    def test_basic(self):
        text = "the the the cat cat sat"
        result = top_n_words(text, 2)
        assert result == [("the", 3), ("cat", 2)]

    def test_default_n(self):
        text = "a b c d e f g"
        result = top_n_words(text)
        assert len(result) == 5

    def test_n_larger_than_unique(self):
        text = "hello world"
        result = top_n_words(text, 10)
        assert len(result) == 2

    def test_empty(self):
        assert top_n_words("", 3) == []


